def _query_to_nested(query: Query) -> QueryNested:
    """Convert flat Query to nested format."""
    attrs = QueryAttributes()
    _populate_query_attrs(attrs, query)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        query, _QUERY_REL_FIELDS, QueryRelationshipAttributes
    )
    return QueryNested(
        guid=query.guid,
        type_name=query.type_name,
        status=query.status,
        version=query.version,
        create_time=query.create_time,
        update_time=query.update_time,
        created_by=query.created_by,
        updated_by=query.updated_by,
        classifications=query.classifications,
        classification_names=query.classification_names,
        meanings=query.meanings,
        labels=query.labels,
        business_attributes=query.business_attributes,
        custom_attributes=query.custom_attributes,
        pending_tasks=query.pending_tasks,
        proxy=query.proxy,
        is_incomplete=query.is_incomplete,
        provenance_type=query.provenance_type,
        home_id=query.home_id,
        depth=query.depth,
        immediate_upstream=query.immediate_upstream,
        immediate_downstream=query.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _query_from_nested(nested: QueryNested) -> Query:
    """Convert nested format to flat Query."""
    attrs = nested.attributes if nested.attributes is not UNSET else QueryAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _QUERY_REL_FIELDS,
        QueryRelationshipAttributes,
    )
    return Query(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_query_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _query_to_nested_bytes(query: Query, serde: Serde) -> bytes:
    """Convert flat Query to nested JSON bytes."""
    return serde.encode(_query_to_nested(query))


def _query_from_nested_bytes(data: bytes, serde: Serde) -> Query:
    """Convert nested JSON bytes to flat Query."""
    nested = serde.decode(data, QueryNested)
    return _query_from_nested(nested)


